operations.reducer:
state.todos.push({
  id: action.input.id,
  title: action.input.title,
  completed: action.input.completed,
});

operations.schema:
input AddTodoInput {
  id: String!
  title: String!
  completed: Boolean!
}

operations.reducer:
const index = state.todos.findIndex(t => t.id === action.input.id);
if (index !== -1) {
  state.todos.splice(index, 1);
}

const todo = state.todos.find(t => t.id === action.input.id);
if (todo) {
  if (action.input.title !== undefined) todo.title = action.input.title;
  if (action.input.completed !== undefined) todo.completed = action.input.completed;
}

